// triskele-vm/src/wolf3d/map.rs
// Author: Echopraxium with the collaboration of Claude AI
// Version: 0.3.0
//
// Wolf3D Episode 1, Level 1 map data.
// Source: Wolfenstein 3D (id Software, 1992) — open source release 1995.
// https://github.com/id-Software/wolf3d
//
// Map is 64×64 cells. Walls encoded as u8:
//   0       = empty floor
//   1..8    = stone wall variants (tile set index)
//   9..16   = wood wall variants
//   17..32  = various wall types
//   128+    = special (doors, etc.) — rendered as solid wall for Phase 1
//
// Player start: cell (29, 22), facing East (angle = 0).

pub const MAP_W: usize = 64;
pub const MAP_H: usize = 64;

/// Returns true if the cell at (x, y) is solid (wall or out-of-bounds).
pub fn is_wall(map: &[u8; MAP_W * MAP_H], x: i32, y: i32) -> bool {
    if x < 0 || y < 0 || x >= MAP_W as i32 || y >= MAP_H as i32 {
        return true;
    }
    map[(y as usize) * MAP_W + (x as usize)] != 0
}

/// Wall tile index at (x, y). 0 = empty.
pub fn tile(map: &[u8; MAP_W * MAP_H], x: i32, y: i32) -> u8 {
    if x < 0 || y < 0 || x >= MAP_W as i32 || y >= MAP_H as i32 {
        return 1;
    }
    map[(y as usize) * MAP_W + (x as usize)]
}

