/// Player start position for E1M1 (world units, cell-centred).
pub const PLAYER_START_X: f32 = 3.5;
pub const PLAYER_START_Y: f32 = 3.5;
/// Initial facing angle in radians (0 = East, positive = CCW).
pub const PLAYER_START_ANGLE: f32 = 0.0;

// ─────────────────────────────────────────────────────────────────────────────
// Wall colour palette — maps tile index → RGBA (simplified, no textures yet)
// Wolf3D used 64×64 textures; Phase 1 uses flat shaded colours per tile type.
// ─────────────────────────────────────────────────────────────────────────────

/// Return wall colour for tile index. North/South faces are darker (× 0.7).
pub fn wall_color(tile: u8, north_south: bool) -> (u8, u8, u8) {
    let (r, g, b) = match tile % 8 {
        0 => (0xAA, 0x55, 0x22),   // grey stone
        1 => (0xCC, 0x99, 0x44),   // wood brown
        2 => (0x99, 0x44, 0x22),   // darker stone
        3 => (0xDD, 0xBB, 0x66),   // light wood
        4 => (0x66, 0x44, 0x22),   // dark brown
        5 => (0x88, 0x88, 0x88),   // grey
        6 => (0xCC, 0x44, 0x44),   // red brick
        _ => (0x44, 0x88, 0xCC),   // blue stone
    };
    if north_south {
        // Darken N/S faces for depth cue
        ((r as u32 * 7 / 10) as u8,
         (g as u32 * 7 / 10) as u8,
         (b as u32 * 7 / 10) as u8)
    } else {
        (r, g, b)
    }
}
